#include<bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=25;
int t,n,f[maxn],a[]= {6,2,5,5,4,5,6,3,7,6};
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>t;
	fill(f+1,f+maxn,INT_MAX);
	for(int i=1; i<10; i++) {
		if(f[a[i]]>i) {
			f[a[i]]=i;
		}
	}
	for(int i=2; i<maxn; i++) {
		for(int j=0; j<10; j++) {
			if(i+a[j]<maxn&&f[i+a[j]]>(10*f[i]+j)) {
				f[i+a[j]]=10*f[i]+j;
			}
		}
	}
	while(t--) {
		cin>>n;
		if(n==1) {
			cout<<-1<<"\n";
		} else if(n<maxn) {
			cout<<f[n]<<"\n";
		} else {
			int c=(n-(maxn-1)+6)/7;
			cout<<f[n-c*7];
			for(int i=1; i<=c; i++) {
				cout<<8;
			}
			cout<<"\n";
		}
	}
	return 0;
}
